// Route the user's message to determine intent
const message = $input.first().json.message?.toLowerCase() || '';

let intent = 'general_query';
let extractedData = {};

// URL qualification
const urlMatch = message.match(/(?:qualify|check|analyze|look at|scan)\s+(?:this\s+)?(?:url\s+)?(?:site\s+)?(https?:\/\/[^\s]+)/i);
if (urlMatch) {
  intent = 'qualify_url';
  extractedData.url = urlMatch[1];
}

// Direct URL paste
const directUrl = message.match(/^(https?:\/\/[^\s]+)$/i);
if (directUrl) {
  intent = 'qualify_url';
  extractedData.url = directUrl[1];
}

// Lead lookup
if (message.match(/show|list|find|get.*lead/i)) {
  intent = 'lead_lookup';
  const scoreMatch = message.match(/(\d+)\+?/);
  if (scoreMatch) extractedData.min_score = parseInt(scoreMatch[1]);
}

// Catalog query
if (message.match(/do we (?:carry|have|stock)|what brands|catalog|brand list/i)) {
  intent = 'catalog_query';
  const brandMatch = message.match(/(?:carry|have|stock)\s+(.+?)\??$/i);
  if (brandMatch) extractedData.brand_query = brandMatch[1].trim();
}

// Add to catalog
if (message.match(/add .+ to (?:catalog|brands|inventory)/i)) {
  intent = 'catalog_update';
}

// Outreach
if (message.match(/write|draft|generate|create.+(?:email|message|outreach|linkedin|dm)/i)) {
  intent = 'generate_outreach';
}

// Stats
if (message.match(/stats|how many|pipeline|funnel|conversion/i)) {
  intent = 'pipeline_stats';
}

return [{
  json: {
    original_message: $input.first().json.message,
    intent: intent,
    extracted_data: extractedData
  }
}];

